      writer.printf("%d\t%d\n",k,v);
    }
    writer.close();
  }
 else {
    CustomWritable key=new CustomWritable();
    CustomWritable value=new CustomWritable();
    DefaultCodec codec=new DefaultCodec();
    codec.setConf(job);
    Writer writer=SequenceFile.createWriter(fs,job,new Path(file.getAbsolutePath()),CustomWritable.class,CustomWritable.class,compressionType,codec);
    for (int k=1, v=100 * fileNum + 1; k <= fileNum; k++, v++) {
      key.set(k);
      value.set(v);
      writer.append(key,value);
    }
    writer.close();
  }
  return new Text(file.getAbsolutePath());
}

