private void writeHugeFile(String fileName,long length) throws IOException {
  Path path=new Path(fileName);
  OutputStream writer=getFileSystem().create(path,false);
  byte[] bytes=new byte[1024];
  while (length > 0) {
    writer.write(bytes);
    length-=bytes.length;
  }
  writer.close();
}

